/* Minimal markdown renderer for the reply popup — zero dependencies by project
 * rule, so no marked/CDN. Covers what Claude replies actually contain: headings,
 * code fences, inline code, bold/italic/strikethrough, links, lists, blockquotes,
 * tables, horizontal rules. Input is HTML-escaped first; the only HTML emitted
 * is generated by this file. */

'use strict';

function escapeHtml(s) {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

/* Lightweight syntax tinting for fenced code — one pass, one combined regex, so
 * comments and strings take precedence and tokens never nest. Input is already
 * HTML-escaped (quotes survive escapeHtml, which only touches & < >). */
const HL_TOKEN = new RegExp(
  '(\\/\\*[\\s\\S]*?\\*\\/|\\/\\/[^\\n]*|#[^\\n]*)' + // comment
  '|("(?:[^"\\\\\\n]|\\\\.)*"|\'(?:[^\'\\\\\\n]|\\\\.)*\'|`(?:[^`\\\\]|\\\\.)*`)' + // string
  '|\\b(\\d+(?:\\.\\d+)?)\\b' + // number
  '|\\b(const|let|var|function|return|if|else|for|while|switch|case|break|continue|class|new|this|import|export|from|async|await|try|catch|finally|throw|typeof|def|self|None|True|False|elif|lambda|null|undefined|true|false|public|private|protected|static|void|int|long|boolean|final|interface|type|struct|func|go|defer|package|chan|map|range|nil|err)\\b', // keyword
  'g'
);

function highlight(code) {
  return code.replace(HL_TOKEN, (m, com, str, num, kw) => {
    const cls = com ? 'hl-com' : str ? 'hl-str' : num ? 'hl-num' : 'hl-kw';
    return '<span class="' + cls + '">' + m + '</span>';
  });
}

/* Inline spans. Order matters: code first so its contents are left verbatim. */
function inline(s) {
  const codes = [];
  s = s.replace(/`([^`]+)`/g, (_, c) => {
    codes.push(c);
    return '\x00' + (codes.length - 1) + '\x00';
  });
  s = s
    .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
    .replace(/__([^_]+)__/g, '<strong>$1</strong>')
    .replace(/(^|\W)\*([^*\s][^*]*)\*/g, '$1<em>$2</em>')
    .replace(/(^|\W)_([^_\s][^_]*)_(?=\W|$)/g, '$1<em>$2</em>')
    .replace(/~~([^~]+)~~/g, '<del>$1</del>')
    .replace(/\[([^\]]+)\]\(([^)\s]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');
  return s.replace(/\x00(\d+)\x00/g, (_, i) => '<code>' + codes[i] + '</code>');
}

function renderMarkdown(src) {
  const lines = escapeHtml(src || '').split('\n');
  const out = [];
  let para = [];
  let list = null; // 'ul' | 'ol'
  let quote = [];

  const flushPara = () => {
    if (para.length) out.push('<p>' + inline(para.join('\n')) + '</p>');
    para = [];
  };
  const flushList = () => {
    if (list) out.push('</' + list + '>');
    list = null;
  };
  const flushQuote = () => {
    if (quote.length) out.push('<blockquote>' + inline(quote.join('\n')) + '</blockquote>');
    quote = [];
  };
  const flushAll = () => { flushPara(); flushList(); flushQuote(); };

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // fenced code block — consume until the closing fence
    const fence = line.match(/^\s*```(\w*)/);
    if (fence) {
      flushAll();
      const body = [];
      while (++i < lines.length && !/^\s*```/.test(lines[i])) body.push(lines[i]);
      const lang = fence[1] ? ' data-lang="' + fence[1] + '"' : '';
      out.push('<pre' + lang + '><code>' + highlight(body.join('\n')) + '</code></pre>');
      continue;
    }

    // table — a header row followed by a |---| separator row
    if (/^\s*\|.*\|\s*$/.test(line) && /^\s*\|[\s\-:|]+\|\s*$/.test(lines[i + 1] || '')) {
      flushAll();
      const cells = (row) => row.trim().replace(/^\||\|$/g, '').split('|').map((c) => inline(c.trim()));
      let html = '<table><thead><tr>' + cells(line).map((c) => '<th>' + c + '</th>').join('') + '</tr></thead><tbody>';
      i++; // skip separator
      while (/^\s*\|.*\|\s*$/.test(lines[i + 1] || '')) {
        html += '<tr>' + cells(lines[++i]).map((c) => '<td>' + c + '</td>').join('') + '</tr>';
      }
      out.push(html + '</tbody></table>');
      continue;
    }

    const heading = line.match(/^(#{1,6})\s+(.*)/);
    if (heading) {
      flushAll();
      const level = heading[1].length;
      out.push(`<h${level}>` + inline(heading[2]) + `</h${level}>`);
      continue;
    }

    if (/^\s*([-*_])\s*\1\s*\1[\s\-*_]*$/.test(line)) { flushAll(); out.push('<hr>'); continue; }

    if (/^\s*&gt;\s?/.test(line)) {
      flushPara(); flushList();
      quote.push(line.replace(/^\s*&gt;\s?/, ''));
      continue;
    }
    flushQuote();

    const item = line.match(/^\s*(?:[-*+]|(\d+)[.)])\s+(.*)/);
    if (item) {
      flushPara();
      const kind = item[1] ? 'ol' : 'ul';
      if (list !== kind) { flushList(); out.push('<' + kind + '>'); list = kind; }
      out.push('<li>' + inline(item[2]) + '</li>');
      continue;
    }
    // indented continuation of the previous list item
    if (list && /^\s{2,}\S/.test(line)) {
      out[out.length - 1] = out[out.length - 1].replace(/<\/li>$/, '<br>' + inline(line.trim()) + '</li>');
      continue;
    }
    flushList();

    if (!line.trim()) { flushPara(); continue; }
    para.push(line);
  }
  flushAll();
  return out.join('\n');
}

// browser uses these as globals; Node (tests) can require them
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { renderMarkdown, highlight, escapeHtml };
}
